<?php
namespace App\Modules\Hr\Compensation\Actions;use App\Modules\Hr\Compensation\Models\HrSalaryBand;use App\Modules\Hr\Compensation\Models\HrSalaryRecord;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Support\Facades\DB;
class ManageSalaryRecordAction{public function __construct(private HrAuditService $audit){}public function propose(HrEmployee $employee,float $gross,string $effectiveFrom,string $reason,?HrSalaryBand $band=null):HrSalaryRecord{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.salary.manage'),403);abort_unless($employee->legal_entity_id===$tenant&&(!$band||$band->legal_entity_id===$tenant),404);abort_if($gross<=0||blank($reason),422);if($band)abort_if($gross<$band->minimum()||$gross>$band->maximum(),422,'Ücret seçilen bandın dışında.');$version=(int)HrSalaryRecord::withoutGlobalScope('tenant')->where('employee_id',$employee->id)->max('version')+1;$row=HrSalaryRecord::create(['legal_entity_id'=>$tenant,'employee_id'=>$employee->id,'salary_band_id'=>$band?->id,'version'=>$version,'gross_salary_encrypted'=>(string)$gross,'currency'=>$band?->currency??'TRY','effective_from'=>$effectiveFrom,'status'=>'pending_approval','change_reason'=>trim($reason),'created_by'=>auth()->id()]);$this->audit->log('salary_change_proposed',$row,null,['gross_salary'=>'[MASKED]']);return $row;}public function approve(HrSalaryRecord $record):HrSalaryRecord{abort_unless(auth()->user()?->hasHrPermission('hr.salary.approve'),403);abort_unless($record->legal_entity_id===app(TenantContext::class)->getId()&&$record->status==='pending_approval',422);abort_if($record->created_by===auth()->id(),422,'Ücret değişikliğini hazırlayan kişi onaylayamaz.');return DB::transaction(function()use($record){HrSalaryRecord::withoutGlobalScope('tenant')->where('employee_id',$record->employee_id)->where('status','approved')->lockForUpdate()->update(['status'=>'superseded']);$record->update(['status'=>'approved','approved_by'=>auth()->id(),'approved_at'=>now()]);$this->audit->log('salary_change_approved',$record,null,['gross_salary'=>'[MASKED]']);return $record->fresh();});}}
